import{_ as a,a as t,b as e,c as n}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as r,o as d,c as l,a2 as u}from"./chunks/framework.DnrXFDHb.js";const j=JSON.parse('{"title":"Redundantní záloha a přepínání zdroje čtení","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/Other/redundant-backup-and-read-source.md","filePath":"cs-CZ/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),s={name:"cs-CZ/Other/redundant-backup-and-read-source.md"};function i(p,o,h,z,b,m){return d(),l("div",null,[...o[0]||(o[0]=[u('<h1 id="redundantni-zaloha-a-prepinani-zdroje-cteni" tabindex="-1">Redundantní záloha a přepínání zdroje čtení <a class="header-anchor" href="#redundantni-zaloha-a-prepinani-zdroje-cteni" aria-label="Permalink to &quot;Redundantní záloha a přepínání zdroje čtení&quot;">​</a></h1><p>Redundantní záloha uloží extra kopii už nahraného souboru.</p><p>Primární soubor i záložní soubor mohou sloužit jako zdroje čtení. Návštěvníci obvykle nepoznají rozdíl. Liší se jen úložný kanál, který soubor obsluhuje.</p><h2 id="co-redundantni-zaloha-umi" tabindex="-1">Co redundantní záloha umí <a class="header-anchor" href="#co-redundantni-zaloha-umi" aria-label="Permalink to &quot;Co redundantní záloha umí&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Funkce</th><th>Popis</th></tr></thead><tbody><tr><td>Uložit extra kopii</td><td>Zálohuje soubory do jiného upload kanálu a snižuje riziko výpadku jednoho kanálu.</td></tr><tr><td>Přepnout zdroj čtení</td><td>Po úspěšné záloze přepne čtení mezi primárním a záložním kanálem.</td></tr><tr><td>Záloha jednoho souboru</td><td>Zálohuje jeden soubor ze stránky detailu souboru.</td></tr><tr><td>Hromadná záloha</td><td>Vyberte více souborů v administraci a zálohujte je společně.</td></tr><tr><td>Globální redundantní záloha</td><td>Zálohuje soubory podle adresáře z Dalších nastavení.</td></tr></tbody></table><h2 id="vstup-pro-redundantni-zalohu" tabindex="-1">Vstup pro redundantní zálohu <a class="header-anchor" href="#vstup-pro-redundantni-zalohu" aria-label="Permalink to &quot;Vstup pro redundantní zálohu&quot;">​</a></h2><p>Otevřete:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Redundant Backup</span></span></code></pre></div><p><img src="'+a+'" alt="Redundantní záloha" loading="lazy"></p><p>Tento vstup je vhodný pro přidání záloh adresáři nebo všem souborům hromadně.</p><p>Záložní kanál můžete vybrat ručně, nebo zvolit automatické přepínání a nechat ImgBed najít vhodný záložní kanál.</p><h2 id="zaloha-z-detailu-souboru" tabindex="-1">Záloha z detailu souboru <a class="header-anchor" href="#zaloha-z-detailu-souboru" aria-label="Permalink to &quot;Záloha z detailu souboru&quot;">​</a></h2><p>Otevřete detail souboru v administraci a klikněte na zálohu.</p><p><img src="'+t+'" alt="Záloha v detailu souboru" loading="lazy"></p><p>Hodí se to pro okamžité zálohování jednoho důležitého souboru.</p><p>Po úspěšné záloze detail souboru zobrazí dostupné zdroje čtení.</p><h2 id="hromadna-zaloha-vyberem" tabindex="-1">Hromadná záloha výběrem <a class="header-anchor" href="#hromadna-zaloha-vyberem" aria-label="Permalink to &quot;Hromadná záloha výběrem&quot;">​</a></h2><p>V administraci vyberte více souborů a spusťte hromadnou zálohu.</p><p><img src="'+e+'" alt="Hromadná záloha" loading="lazy"></p><p>Hodí se to pro zpracování skupiny souborů.</p><p>Záloha z výběru, záloha z detailu souboru a redundantní záloha v Dalších nastaveních používají stejný systém. Jsou to jen různé vstupy.</p><h2 id="prepnuti-zdroje-cteni-po-zaloze" tabindex="-1">Přepnutí zdroje čtení po záloze <a class="header-anchor" href="#prepnuti-zdroje-cteni-po-zaloze" aria-label="Permalink to &quot;Přepnutí zdroje čtení po záloze&quot;">​</a></h2><p>Po dokončení zálohy umožní detail souboru přepnout zdroj čtení:</p><table tabindex="0"><thead><tr><th>Zdroj čtení</th><th>Popis</th></tr></thead><tbody><tr><td>Primární kanál</td><td>Čte z původního upload kanálu.</td></tr><tr><td>Záložní kanál</td><td>Čte z kanálu, kde je redundantní kopie.</td></tr></tbody></table><p><img src="'+n+'" alt="Přepnutí zdroje čtení po záloze" loading="lazy"></p><p>Návštěvníci nemusí vědět, zda je soubor obsluhovaný z primárního nebo záložního kanálu.</p><p>Zvolený zdroj čtení se stane preferovaným zdrojem pro pozdější přístup k souboru.</p><h2 id="kdy-se-zaloha-preskoci" tabindex="-1">Kdy se záloha přeskočí <a class="header-anchor" href="#kdy-se-zaloha-preskoci" aria-label="Permalink to &quot;Kdy se záloha přeskočí&quot;">​</a></h2><p>Následující situace se při zálohování přeskočí. Nejde o chyby.</p><table tabindex="0"><thead><tr><th>Situace</th><th>Proč se přeskočí</th></tr></thead><tbody><tr><td>Už je zálohováno</td><td>Soubor, který už má zálohu, se nezálohuje znovu.</td></tr><tr><td>Primární a záložní kanál jsou stejné</td><td>Záloha má smysl jen v jiném kanálu.</td></tr><tr><td>Není použitelný záložní kanál</td><td>Není dostupný vhodný alternativní kanál.</td></tr></tbody></table><p>Stručně: zálohy musí jít do jiného kanálu a už zálohované soubory znovu nespotřebují další místo.</p><h2 id="primarni-a-zalozni-kanal" tabindex="-1">Primární a záložní kanál <a class="header-anchor" href="#primarni-a-zalozni-kanal" aria-label="Permalink to &quot;Primární a záložní kanál&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Název</th><th>Význam</th></tr></thead><tbody><tr><td>Primární kanál</td><td>Kanál použitý při prvním uploadu souboru.</td></tr><tr><td>Záložní kanál</td><td>Kanál, který ukládá redundantní kopii.</td></tr><tr><td>Primární zdroj čtení</td><td>Soubor se aktuálně čte z primárního kanálu.</td></tr><tr><td>Záložní zdroj čtení</td><td>Soubor se aktuálně čte ze záložního kanálu.</td></tr></tbody></table><p>Primární i záložní zdroj čtení se pro uživatele chovají stejně.</p><p>Dokud je záložní soubor dostupný, obrázky, videa a odkazy ke stažení fungují i po přepnutí na záložní zdroj čtení.</p><h2 id="co-se-stane-pri-smazani-souboru" tabindex="-1">Co se stane při smazání souboru <a class="header-anchor" href="#co-se-stane-pri-smazani-souboru" aria-label="Permalink to &quot;Co se stane při smazání souboru&quot;">​</a></h2><p>Když se soubor smaže, ImgBed smaže primární soubor i záložní soubor.</p>',37)])])}const v=r(s,[["render",i]]);export{j as __pageData,v as default};
